/* ─────────────────────────────────────────────────────────────
   SHEET-NAME MATCHING
   Excel truncates sheet names to 31 chars.
   Match: exact → dim-starts-with-sheet → sheet-starts-with-dim
   ───────────────────────────────────────────────────────────── */
function findSheetForDim(sheetNames, dim) {
