/* ─────────────────────────────────────────────────────────────
   RATING NORMALISER
   Accepts: "Adhoc" / "ADHOC" / "1" / 1 → canonical label
   ───────────────────────────────────────────────────────────── */
function normaliseRating(raw) {
  if (raw === null || raw === undefined || raw === '') return null;
  const s = String(raw).trim();
  const exact = RATING_LABELS.find(r => r.toLowerCase() === s.toLowerCase());
